options.rootCSS:
html, body {
  height: 100%;
  margin: 0;
  padding: 0;
  font-family: 'Segoe UI', sans-serif;
  background: linear-gradient(135deg, #1d3946 0%, #121c2d 100%);
  backdrop-filter: blur(8px);
  color: #ffffff;
  box-sizing: border-box;
}

/* Painéis com efeito vidro na versão 11 */
div[class*="-panel-content"][data-testid*="panel content"] {
  background: rgba(10, 45, 59, 0.801) !important;
  border: 1px solid rgba(86, 213, 220, 0.2);
  border-radius: 6px;
  backdrop-filter: blur(10px);
  box-shadow: 0 0 8px rgba(0, 255, 255, 0.02);
  overflow: hidden;
  transition: all 0.3s ease-in-out;
  will-change: box-shadow, border-color;
}

/* Hover com destaque */
div[class*="-panel-content"][data-testid*="panel content"]:hover {
  box-shadow: 0 0 25px rgba(0, 255, 255, 0.15);
  border-color: rgba(0, 255, 255, 0.2);
}

options.getOption:
const series = context.panel.data.series.map((s) => {
  const sData = s.fields.find((f) => f.type === 'number').values.buffer || s.fields.find((f) => f.type === 'number').values;
  const sTime = s.fields.find((f) => f.type === 'time').values.buffer || s.fields.find((f) => f.type === 'time').values;

  return {
    name: s.refId,
    type: 'line',
    showSymbol: false,
    areaStyle: {
      opacity: 0.1,
    },
    lineStyle: {
      width: 1,
    },
    data: sData.map((d, i) => [sTime[i], d.toFixed(2)]),
  };
});

/**
 * Enable Data Zoom by default
 */
setTimeout(() => context.panel.chart.dispatchAction({
  type: 'takeGlobalCursor',
  key: 'dataZoomSelect',
  dataZoomSelectActive: true,
}), 500);

/**
 * Update Time Range on Zoom
 */
context.panel.chart.on('datazoom', function (params) {
  const startValue = params.batch[0]?.startValue;
  const endValue = params.batch[0]?.endValue;
  locationService.partial({ from: startValue, to: endValue });
});

return {
  backgroundColor: 'transparent',
  tooltip: {
    trigger: 'axis',
  },
  legend: {
    left: '0',
    bottom: '0',
    data: context.panel.data.series.map((s) => s.refId),
    textStyle: {
      color: 'rgba(128, 128, 128, .9)',
    },
  },
  toolbox: {
    feature: {
      dataZoom: {
        yAxisIndex: 'none',
        icon: {
          zoom: 'path://',
          back: 'path://',
        },
      },
      saveAsImage: {},
    }
  },
  xAxis: {
    type: 'time',
  },
  yAxis: {
    type: 'value',
    min: 'dataMin',
  },
  grid: {
    left: '2%',
    right: '2%',
    top: '2%',
    bottom: 24,
    containLabel: true,
  },
  series,
};

