// Coleta valor mais recente em segundos
const uptimeSeconds = Number(
  context.panel.data.series?.[0]?.fields.find(f => f.type === 'number')?.values?.at(-1)
) || 0;

const width = context.width || 306;
const height = context.height || 103;

// Converte segundos para formato "Xd HH:MM:SS"
const formatUptime = (totalSeconds) => {
  let s = totalSeconds;
  const d = Math.floor(s / 86400); s -= d * 86400;
  const h = String(Math.floor(s / 3600)).padStart(2, '0'); s %= 3600;
  const m = String(Math.floor(s / 60)).padStart(2, '0'); s %= 60;
  const sec = String(Math.floor(s)).padStart(2, '0');
  return `${d}d ${h}:${m}:${sec}`;
};

const panel = {
  graphic: [
    // Borda externa
    {
      type: 'rect',
      shape: { x: 0, y: 0, width, height, r: 10 },
      style: {
        fill: 'transparent',
        lineWidth: 0.3,
        shadowBlur: 15,
        shadowOffsetX: 0,
        shadowOffsetY: 0
      },
      z: -10
    },
    // Fundo com gradiente
    {
      type: 'rect',
      left: '10%',
      top: '10%',
      width: '80%',
      height: '80%',
      style: {
        fill: {
          type: 'linear',
          x: 0, y: 0, x2: 1, y2: 1,
          colorStops: [
            { offset: 0, color: 'rgba(255,255,255,0.06)' },
            { offset: 1, color: 'rgba(255,255,255,0.02)' }
          ]
        },
        borderRadius: 5,
        border: '1px solid rgba(255,255,255,0.1)'
      }
    },
    // Ícone
    {
      type: 'image',
      left: '12%',
      top: '25%',
      style: {
        width: 65,
        height: 45
      },
      z: 10
    },
    // Texto: Uptime formatado
    {
      type: 'text',
      left: '68%',
      top: '29%',
      style: {
        text: formatUptime(uptimeSeconds),
        fontSize: 17,
        fontWeight: 'bold',
        textAlign: 'center',
        fill: '#56d5dc'
      },
      z: 10
    },
    // Texto auxiliar
    {
      type: 'text',
      left: '5%',
      top: '35%',
      style: {
        text: 'System Uptime',
        fontSize: 13,
        fontWeight: 'bold',
        fill: '#FFFFFF',
        textAlign: 'center'
      },
      z: 10
    },
    // Linha decorativa
    {
      type: 'rect',
      left: '57%',
      top: '70%',
      width: 40,
      height: 2,
      style: {
        fill: {
          type: 'linear',
          x: 0, y: 0, x2: 1, y2: 0,
          colorStops: [
            { offset: 0, color: 'rgba(255, 255, 255, 0)' },
            { offset: 1, color: 'transparent' }
          ]
        },
        borderRadius: 2
      },
      z: 10
    }
  ],
  animation: true,
  animationDuration: 500,
  animationEasing: 'cubicOut'
};

// Hover: efeito de brilho
const applyHover = (blur) => {
  const updated = panel.graphic.map(el => {
    if (el.type === 'rect' && el.shape) {
      return {
        ...el,
        style: { ...el.style, shadowBlur: blur }
      };
    }
    return el;
  });
  context.panel.chart.setOption({ graphic: updated });
};

context.panel.chart.on('mouseover', () => applyHover(25));
context.panel.chart.on('mouseout', () => context.panel.chart.setOption(panel));

return panel;

options.onInit:
console.log("📡 Dados recebidos:", data);

const htmlgraphicsValue = htmlNode.getElementById('htmlgraphics-value');
if (!htmlgraphicsValue || !data.series?.length) return;

// Cria mapa de interfaces com valores
const interfaceMap = {};

data.series.forEach(serie => {
  const metricLabel = serie.fields.find(f => f.name === 'metric')?.values?.[0] || '';
  const interfaceLabel = serie.fields.find(f => f.name === 'interface')?.values?.[0] || 'N/A';
  const valueField = serie.fields.find(f => f.name === 'value');
  const lastValue = valueField?.values?.get(valueField.values.length - 1);

  if (!interfaceMap[interfaceLabel]) {
    interfaceMap[interfaceLabel] = {};
  }

  if (/rx/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Rx = lastValue;
  } else if (/tx/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Tx = lastValue;
  } else if (/temperature|temperatura/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Temperature = lastValue;
  }
});

// Gera HTML da tabela
let tableHTML = `
  <table style="width: 100%; border-collapse: collapse; color: white; text-align: center; font-size: 12px;">
    <thead>
      <tr style="background: #00000e;">
        <th style="padding: 3px 8px;">Interface</th>
        <th style="padding: 3px 8px;">Rx Power</th>
        <th style="padding: 3px 8px;">Tx Power</th>
        <th style="padding: 3px 8px;">Temperatura</th>
      </tr>
    </thead>
    <tbody>
`;

Object.entries(interfaceMap).forEach(([iface, values]) => {
  tableHTML += `
    <tr>
      <td style="padding: 3px 8px;">${iface}</td>
      <td style="padding: 3px 8px;">${values.Rx ?? 'N/A'} dBm</td>
      <td style="padding: 3px 8px;">${values.Tx ?? 'N/A'} dBm</td>
      <td style="padding: 3px 8px;">${values.Temperature ?? 'N/A'} °C</td>
    </tr>
  `;
});

tableHTML += `
    </tbody>
  </table>
`;

htmlgraphicsValue.innerHTML = tableHTML;

options.onRender:
function getColor(value, limits) {
  if (value === undefined || isNaN(value)) return "#b0bec5";
  for (const [limit, color] of limits) if (value <= limit) return color;
  return limits[limits.length - 1][1];
}

function getRxColor(value) {
  return getColor(value, [[-40, "#ff1744"], [-30, "#ffca28"], [Infinity, "#00e676"]]);
}

function getTxColor(value) {
  return getColor(value, [[-10, "#d32f2f"], [-1, "#00e676"], [0.5, "#fbc02d"]]);
}

function getQFactorColor(value) {
  return getColor(value, [[6, "#d32f2f"], [7.5, "#fbc02d"], [Infinity, "#00e676"]]);
}

function getStatusColor(status) {
  if (!status) return "#b0bec5";
  const normalized = status.toString().toLowerCase();
  if (normalized.includes("down") || normalized.includes("alarme")) return "#d32f2f";
  if (normalized.includes("up")) return "#00e676";
  return "#fbc02d";
}

const tbody = htmlNode.querySelector("tbody");
if (!tbody || !data.series?.length) return;

const itemField = data.series[0].fields.find(f => f.name.toLowerCase().includes("item"));
const valueField = data.series[0].fields.find(f => f.name.toLowerCase().includes("last"));
if (!itemField || !valueField) return;

const itemValues = itemField.values;
const valueValues = valueField.values;

const ifaceMap = {};

for (let i = 0; i < itemValues.length; i++) {
  const raw = itemValues.get(i);
  const value = valueValues.get(i);

  if (!raw || value === null || value === undefined) continue;

  // Captura nomes como PORT-1/2, PTP-1/2, etc + rxMin, tx, QFactor...
  const match = raw.match(/(PORT-[\d\/]+|PTP-[\d\/]+)(.*)?(rx|min|qfactor|status)/i);
  if (!match) continue;

  const iface = match[1].trim();
  let metric = match[3]?.toLowerCase() ?? "";

  if (!ifaceMap[iface]) ifaceMap[iface] = {};

  if (metric.includes("rx")) {
    ifaceMap[iface].rx = value;
  } else if (metric.includes("qfactor")) {
    ifaceMap[iface].qfactor = value;
  } else if (metric.includes("status")) {
    ifaceMap[iface].status = value;
  }
}

// Monta a tabela final com QFactor formatado
let html = "";
Object.entries(ifaceMap).forEach(([iface, metrics]) => {
  const qfactorDisplay = metrics.qfactor !== undefined ? Number(metrics.qfactor).toFixed(2) : 'N/A';
  const qfactorColor = getQFactorColor(metrics.qfactor);

  html += `
    <tr>
      <td><b>${iface}</b></td>
      <td style="color:${qfactorColor}; font-weight:bold;">${qfactorDisplay}</td>
    </tr>
  `;
});

tbody.innerHTML = html;

