visualEditor.code:
const seriesRaw = context?.panel?.data?.series || [];
const timeField = seriesRaw[0]?.fields.find(f => f.type === 'time');
if (!timeField) return { series: [] };

// 🔹 Formatador de Q-Factor (dB)
const formatQFactor = v =>
  typeof v === 'number' ? `${v.toFixed(2)} dB` : 'N/A';

// 🔹 Variação de cor por canal
const adjustColor = (hex, factor = 1) => {
  const f = parseInt(hex.slice(1), 16);
  const r = Math.min(255, Math.round(((f >> 16) & 255) * factor));
  const g = Math.min(255, Math.round(((f >> 8) & 255) * factor));
  const b = Math.min(255, Math.round((f & 255) * factor));
  return `rgb(${r},${g},${b})`;
};

// 🔹 Paletas fixas por interface
const baseColors100GE = {
  '100GEO/0/0': '#00FFC6',
  '100GEO/0/1': '#6AD1FF',
  '100GEO/0/2': '#9966FF',
  '100GEO/0/3': '#FFB800'
};

const defaultPalette = ['#FF4D4D', '#66CCFF', '#FFCC00', '#33CC33'];
let colorIndex = 0;

const getLineColor = (name) => {
  const lane = name.match(/Lane\s?(\d)/i)?.[1] ?? '';
  const iface = name.match(/100GEO\/[\d/]+/i)?.[0];
  if (iface && baseColors100GE[iface]) {
    return adjustColor(baseColors100GE[iface], 1 - (parseInt(lane) * 0.15));
  }
  return defaultPalette[colorIndex++ % defaultPalette.length];
};

// 🔹 Monta todas as séries de Q-Factor
const allSeries = seriesRaw.flatMap((serie) => {
  const time = serie.fields.find(f => f.type === 'time');
  if (!time) return [];

  return serie.fields
    .filter(f =>
      f.type === 'number' &&
      /factor/i.test(f.name) &&
      !/error|correction|fec/i.test(f.name)
    )
    .map(field => {
      const values = field.values;
      const last = values.at(-1);
      const hasValue = values.some(v => typeof v === 'number' && !isNaN(v));
      if (!hasValue) return null;

      const base = field.name.split(':')[0]?.trim() || field.name;
      const lane = field.name.match(/Lane\s?(\d)/i)?.[1];
      const laneLabel = lane ? ` - Lane ${lane}` : '';
      const label = formatQFactor(last);

      return {
        name: `${base}${laneLabel} | ${label}`,
        type: 'line',
        smooth: true,
        showSymbol: false,
        sampling: 'lttb',
        lineStyle: { width: 1.1, color: getLineColor(field.name) },
        emphasis: { focus: 'series' },
        data: values.map((v, i) => [time.values[i], v])
      };
    })
    .filter(Boolean);
});

// 🔹 Configuração completa do gráfico
return {
  title: {
    text: 'Q-Factor por Canal',
    subtext: 'Monitoramento Dinâmico',
    left: 'center',
    top: 10,
    textStyle: {
      color: '#E8F0F2',
      fontSize: 15,
      fontWeight: 'bold'
    },
    subtextStyle: {
      color: '#AAAAAA',
      fontSize: 11
    }
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'cross' },
    backgroundColor: 'rgba(0,0,0,0.9)',
    textStyle: { color: '#ffffff' },
    formatter: (params) => {
      if (!params?.length || !params[0].value) return '';
      const { seriesName, value, color } = params[0];
      const date = new Date(value[0]);
      const val = typeof value[1] === 'number' ? formatQFactor(value[1]) : 'N/A';
      const alerta = value[1] < 6.5
        ? ' <span style="color:#FF4D4D">⚠ Baixa Qualidade de Sinal</span>'
        : value[1] < 7.5
          ? ' <span style="color:#FFC107">⚠ Atenção</span>'
          : '';
      return `Horário: ${date.toLocaleTimeString()}<br/><span style="color:${color}">●</span> ${seriesName} <b>${val}</b>${alerta}`;
    }
  },
  legend: {
    type: 'scroll',
    orient: 'horizontal',
    top: 'bottom',
    textStyle: {
      color: '#E8F0F2',
      fontSize: 11
    },
    itemHeight: 6,
    itemWidth: 12,
    itemGap: 20,
    selector: [
      { type: 'all', title: 'Selecionar Tudo' },
      { type: 'inverse', title: 'Desmarcar Tudo' }
    ],
    inactiveColor: '#888'
  },
  grid: {
    left: '3%',
    right: '3%',
    top: '21%',
    bottom: '14%',
    containLabel: true
  },
  xAxis: {
    type: 'time',
    axisLine: { lineStyle: { color: '#E8F0F2' } },
    axisLabel: {
      color: '#CCCCCC',
      formatter: v => {
        const d = new Date(v);
        return `${d.getHours()}:${String(d.getMinutes()).padStart(2, '0')}`;
      }
    },
    splitLine: { show: false }
  },
  yAxis: {
    type: 'value',
    name: 'Q-Factor (dB)',
    nameTextStyle: {
      color: '#E8F0F2',
      fontSize: 12
    },
    axisLabel: {
      color: '#CCCCCC',
      formatter: formatQFactor
    },
    axisLine: { lineStyle: { color: '#E8F0F2' } },
    splitLine: {
      show: true,
      lineStyle: {
        color: 'rgba(255,255,255,0.05)',
        type: 'dashed'
      }
    }
  },
  series: allSeries
};

