const seriesRaw = context?.panel?.data?.series || [];
const timeField = seriesRaw[0]?.fields.find(f => f.type === 'time');
if (!timeField) return { series: [] };

// 🔹 Formatador de sinal óptico (dBm)
const formatSignal = v =>
  typeof v === 'number' ? `${v.toFixed(2)} dBm` : 'N/A';

// 🔹 Ajuste de cor baseado em RGB
const adjustColor = (hex, factor = 1) => {
  const f = parseInt(hex.slice(1), 16);
  const r = Math.min(255, Math.round(((f >> 16) & 255) * factor));
  const g = Math.min(255, Math.round(((f >> 8) & 255) * factor));
  const b = Math.min(255, Math.round((f & 255) * factor));
  return `rgb(${r},${g},${b})`;
};

const defaultPalette = ['#FF4D4D', '#66CCFF', '#FFCC00', '#33CC33', '#00FFC6', '#9966FF', '#FFB800'];
let colorIndex = 0;
const getLineColor = () => defaultPalette[colorIndex++ % defaultPalette.length];

// 🔹 Geração das séries
const allSeries = seriesRaw.flatMap((serie) => {
  const time = serie.fields.find(f => f.type === 'time');
  if (!time) return [];

  return serie.fields
    .filter(f =>
      f.type === 'number' &&
      /(tx|rx)/i.test(f.name) // Busca por qualquer item com tx ou rx
    )
    .map(field => {
      const values = field.values;
      const last = values.at(-1);
      const hasValue = values.some(v => typeof v === 'number' && !isNaN(v));
      if (!hasValue) return null;

      // Extrai o nome do PTP-x/y
      const ptpMatch = field.name.match(/(PTP-\d+\/\d+)/i);
      const ptpLabel = ptpMatch ? ptpMatch[1] : field.name.split(':')[0];

      // Define direção e nome
      const direction = /tx/i.test(field.name) ? 'Tx' : 'Rx';
      const label = formatSignal(last);

      return {
        name: `${ptpLabel} ${direction} | ${label}`,
        type: 'line',
        smooth: true,
        showSymbol: false,
        sampling: 'lttb',
        lineStyle: { width: 1.1, color: getLineColor() },
        emphasis: { focus: 'series' },
        data: values.map((v, i) => [time.values[i], v])
      };
    })
    .filter(Boolean);
});

// 🔹 Configuração final
return {
  title: {
    text: 'Potência Óptica (Rx/Tx)',
    subtext: 'Monitoramento PTP-x/y',
    left: 'center',
    top: 10,
    textStyle: {
      color: '#E8F0F2',
      fontSize: 15,
      fontWeight: 'bold'
    },
    subtextStyle: {
      color: '#AAAAAA',
      fontSize: 11
    }
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'cross' },
    backgroundColor: 'rgba(0,0,0,0.9)',
    textStyle: { color: '#ffffff' },
    formatter: (params) => {
      if (!params?.length || !params[0].value) return '';
      const { seriesName, value, color } = params[0];
      const date = new Date(value[0]);
      const val = typeof value[1] === 'number' ? formatSignal(value[1]) : 'N/A';
      const alerta = value[1] < -10
        ? ' <span style="color:#FF4D4D">⚠ Sinal Crítico</span>' : '';
      return `Horário: ${date.toLocaleTimeString()}<br/><span style="color:${color}">●</span> ${seriesName} <b>${val}</b>${alerta}`;
    }
  },
  legend: {
    type: 'scroll',
    orient: 'horizontal',
    top: 'bottom',
    textStyle: {
      color: '#E8F0F2',
      fontSize: 11
    },
    itemHeight: 6,
    itemWidth: 12,
    itemGap: 20,
    selector: [
      { type: 'all', title: 'Selecionar Tudo' },
      { type: 'inverse', title: 'Desmarcar Tudo' }
    ],
