console.log("📡 Dados recebidos:", data);

const htmlgraphicsValue = htmlNode.getElementById('htmlgraphics-value');
if (!htmlgraphicsValue || !data.series?.length) return;

// Cria mapa de interfaces com valores
const interfaceMap = {};

data.series.forEach(serie => {
  const metricLabel = serie.fields.find(f => f.name === 'metric')?.values?.[0] || '';
  const interfaceLabel = serie.fields.find(f => f.name === 'interface')?.values?.[0] || 'N/A';
  const valueField = serie.fields.find(f => f.name === 'value');
  const lastValue = valueField?.values?.get(valueField.values.length - 1);

  if (!interfaceMap[interfaceLabel]) {
    interfaceMap[interfaceLabel] = {};
  }

  if (/rx/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Rx = lastValue;
  } else if (/tx/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Tx = lastValue;
  } else if (/temperature|temperatura/i.test(metricLabel)) {
    interfaceMap[interfaceLabel].Temperature = lastValue;
  }
});

