      padding: [2, 8]
    },
    inactiveColor: '#bbbbbb'
  },
  grid: {
    left: '3%',
    right: '2%',
    top: '15%',
    bottom: '20%', // espaço aumentado
    containLabel: true
  },
  xAxis: {
    type: 'time',
    axisLine: { lineStyle: { color: 'rgba(255,255,255,0.1)' } },
    axisLabel: {
