// 🔹 Formatador de tráfego
function formatThroughput(v) {
  if (v >= 1e9) return (v / 1e9).toFixed(v % 1e9 === 0 ? 0 : 2) + ' Gb/s';
  if (v >= 1e6) return (v / 1e6).toFixed(v % 1e6 === 0 ? 0 : 2) + ' Mb/s';
  if (v >= 1e3) return (v / 1e3).toFixed(v % 1e3 === 0 ? 0 : 2) + ' Kb/s';
  return v.toFixed(0) + ' b/s';
}

// 🔹 Cores harmônicas com o tema do dashboard
const getLineColor = (name) => {
  const baseColors = ['#2ec4b6', '#3a86ff', '#56d5dc', '#00b3a4', '#4cc9f0', '#5eead4'];
  const hash = name.split('').reduce((a, b) => a + b.charCodeAt(0), 0);
  return baseColors[hash % baseColors.length];
};

const seriesRaw = context?.panel?.data?.series || [];
const timeField = seriesRaw[0]?.fields.find(f => f.type === 'time');
if (!timeField) return { series: [] };

// 🔹 Monta as séries somente com "Bits sent"
const series = seriesRaw.flatMap((serie) => {
  const time = serie.fields.find(f => f.type === 'time');
  if (!time) return [];

  return serie.fields
    .filter(f => f.type === 'number' && /Bits sent/i.test(f.name)) // <-- Filtro só para SENT
    .map(field => {
      const values = field.values;
      const last = values.at(-1);
      const hasTraffic = values.some(v => typeof v === 'number' && !isNaN(v) && v > 0);
      if (!hasTraffic) return null;

      const max = Math.max(...values.filter(v => typeof v === 'number' && !isNaN(v)));
      const label = typeof last === 'number' ? formatThroughput(last) : 'N/A';
      const base = field.name.split(':')[0].trim();
      const color = getLineColor(field.name);

      return {
        name: `${base} (Sent) | ${label}`,
        type: 'line',
        smooth: true,
        showSymbol: false,
        sampling: 'lttb',
        lineStyle: { width: 1.4, color },
        areaStyle: { opacity: 0.08, color },
        emphasis: { focus: 'series' },
        data: values.map((v, i) => [time.values[i], v]),
        _max: max
      };
    })
    .filter(Boolean);
}).toSorted((a, b) => b._max - a._max)
  .map(({ _max, ...rest }) => rest);

// 🔹 Config final
return {
  title: {
    text: 'Tráfego por Interface (Sent)',
    left: 'center',
    top: 10,
    textStyle: {
      color: '#ffffff',
      fontSize: 15,
      fontWeight: 'bold'
    }
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'cross' },
    triggerOn: 'mousemove',
    showContent: true,
    backgroundColor: 'rgba(0,0,0,0.7)',
    textStyle: { color: '#ffffff' },
    formatter: (params) => {
      if (!params?.length || !params[0].value) return '';
      const { seriesName, value, color } = params[0];
      const date = new Date(value[0]);
      const val = typeof value[1] === 'number' ? formatThroughput(value[1]) : 'N/A';
      return `Horário: ${date.toLocaleTimeString()}<br/><span style="color:${color}">●</span> ${seriesName} <b>${val}</b>`;
    }
  },
  legend: {
    type: 'scroll',
    orient: 'horizontal',
    top: 'bottom',
    textStyle: {
      color: '#dddddd',
      fontSize: 11
    },
    itemHeight: 6,
    itemWidth: 12,
    itemGap: 25,
    padding: [5, 20],
    pageScroll: true,
    scrollDataIndex: 0,
    pageButtonItemGap: 10,
    pageIconColor: '#56d5dc',
    pageTextStyle: { color: '#aaa' },
    backgroundColor: 'rgba(20, 20, 20, 0.25)',
    borderRadius: 8,
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.2)',
    selector: [
      { type: 'all', title: 'Selecionar Tudo' },
      { type: 'inverse', title: 'Desmarcar Tudo' }
    ],
    selectorLabel: {
      show: true,
      color: '#ffffff',
      borderColor: 'rgba(255,255,255,0.3)',
      borderWidth: 1,
      borderRadius: 6,
      backgroundColor: 'rgba(40, 40, 40, 0.3)',
      padding: [2, 8]
    },
    inactiveColor: '#bbbbbb'
  },
  grid: {
    left: '3%',
    right: '2%',
    top: '15%',
    bottom: '18%',
    containLabel: true
  },
  xAxis: {
    type: 'time',
    axisLine: { lineStyle: { color: 'rgba(255,255,255,0.1)' } },
    axisLabel: {
      color: '#aaa',
      formatter: v => {
        const d = new Date(v);
        return `${d.getHours()}:${String(d.getMinutes()).padStart(2, '0')}`;
      }
    },
    splitLine: { show: false }
  },
  yAxis: {
    type: 'value',
    name: 'Tráfego',
    nameTextStyle: {
      color: '#ffffff',
      fontSize: 12
    },
