const series = context?.panel?.data?.series || [];

const errors = series.flatMap(serie => {
  const timeField = serie.fields.find(f => f.type === 'time');
  if (!timeField) return [];

  return serie.fields
    .filter(f =>
      f.type === 'number' &&
      /Outbound\s+errors/i.test(f.name)
    )
    .map(field => {
      const last = parseFloat(field.values.at(-1));
      if (isNaN(last)) return null;

      const match = field.name.match(/PORT-[1-5]\/\d+/i);
      const port = match ? match[0] : field.name;

      return {
        name: port,
        value: last
      };
    })
    .filter(Boolean);
});

const top5 = errors
  .toSorted((a, b) => b.value - a.value)
  .slice(0, 5);

const worst = top5[0]; // Interface com mais erro

return {
  title: {
    text: 'Top 5 Out Errors (CIENA)',
    left: 'center',
    top: 10,
    textStyle: { color: '#ffffff', fontSize: 14, fontWeight: 'bold' },
    subtext: worst ? `Pior porta: ${worst.name} com ${worst.value.toLocaleString('pt-BR')} erros` : '',
    subtextStyle: {
      color: '#ffcc80',
      fontSize: 12,
      fontWeight: 'normal'
    }
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'shadow' },
    backgroundColor: 'rgba(0,0,0,0.75)',
